const response = hopp.response.body.asJSON();

hopp.test("Status is 200", () => {
  hopp.expect(hopp.response.statusCode).toBe(200);
});

hopp.test("Response contains product collection", () => {
  hopp.expect(response).toBeType("object");
  hopp.expect(Array.isArray(response.data)).toBe(true);
});

const response = hopp.response.body.asJSON();
const product = response.data || {};

hopp.test("Status is 201", () => {
  hopp.expect(hopp.response.statusCode).toBe(201);
});

hopp.test("Product is created", () => {
  hopp.expect(product).toBeType("object");
  hopp.expect(product.id).toBeType("number");
  hopp.expect(product.name).toBe("Gaming Keyboard");
  hopp.expect(product.stock).toBe(15);
});

if (product.id) {
  hopp.env.set("productId", String(product.id));
}

const response = hopp.response.body.asJSON();
const product = response.data || {};
const expectedProductId = Number(hopp.env.get("productId"));

hopp.test("Status is 200", () => {
  hopp.expect(hopp.response.statusCode).toBe(200);
});

hopp.test("Product id matches productId", () => {
  hopp.expect(product.id).toBe(expectedProductId);
});

const response = hopp.response.body.asJSON();
const product = response.data || {};
const expectedProductId = Number(hopp.env.get("productId"));

hopp.test("Status is 200", () => {
  hopp.expect(hopp.response.statusCode).toBe(200);
});

hopp.test("Product is updated", () => {
  hopp.expect(product.id).toBe(expectedProductId);
  hopp.expect(product.name).toBe("Updated Gaming Keyboard");
  hopp.expect(product.stock).toBe(10);
});

const response = hopp.response.body.asJSON();
const product = response.data || {};
const expectedProductId = Number(hopp.env.get("productId"));

hopp.test("Status is 200", () => {
  hopp.expect(hopp.response.statusCode).toBe(200);
});

hopp.test("Product stock is patched", () => {
  hopp.expect(product.id).toBe(expectedProductId);
  hopp.expect(product.stock).toBe(25);
});

const response = hopp.response.body.asJSON();
const errors = response.errors || {};

hopp.test("Status is 422", () => {
  hopp.expect(hopp.response.statusCode).toBe(422);
});

hopp.test("Validation errors are returned", () => {
  hopp.expect(errors).toBeType("object");
  hopp.expect(Array.isArray(errors.name)).toBe(true);
  hopp.expect(Array.isArray(errors.price)).toBe(true);
  hopp.expect(Array.isArray(errors.stock)).toBe(true);
});
